// EDIT THIS: one row per Airbnb listing -> Splynx customer + bundle.
// customer_id is the Splynx customer id; bundle drives the ACTIVE charge.
const LISTINGS = [
  { listing: 'Kololo Apt 1', ical_url: 'https://www.airbnb.com/calendar/ical/XXXX.ics?s=AAAA', customer_id: 101, bundle: 'weekend' },
  { listing: 'Entebbe Studio', ical_url: 'https://www.airbnb.com/calendar/ical/YYYY.ics?s=BBBB', customer_id: 102, bundle: 'weekend' }
];
return LISTINGS.map(json => ({ json }));

// Correlate each iCal response to its listing by index (Fetch iCal has
// neverError=true so failed fetches still yield an item, keeping alignment).
const listings = $('Listings').all();
const responses = $input.all();
const pad = n => String(n).padStart(2, '0');
// 'today' in EAT (UTC+3)
const now = new Date(Date.now() + 3 * 3600 * 1000);
const today = `${now.getUTCFullYear()}${pad(now.getUTCMonth() + 1)}${pad(now.getUTCDate())}`;
const store = $getWorkflowStaticData('global');
const out = [];
for (let i = 0; i < responses.length; i++) {
  const meta = (listings[i] && listings[i].json) || {};
  if (!meta.customer_id) continue;
  const r = responses[i].json;
  const ical = r.data || r.body || (typeof r === 'string' ? r : '') || '';
  const blocks = String(ical).split('BEGIN:VEVENT').slice(1);
  for (const blk of blocks) {
    const ds = (blk.match(/DTSTART[^:]*:(\d{8})/) || [])[1];
    const de = (blk.match(/DTEND[^:]*:(\d{8})/) || [])[1];
    const uid = ((blk.match(/UID:([^\r\n]+)/) || [])[1] || `${ds}-${de}`).trim();
    if (ds === today) {
      const k = `${meta.customer_id}|${uid}|ACTIVE`;
      if (!store[k]) { store[k] = Date.now(); out.push({ json: { customer_id: meta.customer_id, target_tier: 'ACTIVE', bundle: meta.bundle || 'weekend' } }); }
    }
    if (de === today) {
      const k = `${meta.customer_id}|${uid}|IDLE`;
      if (!store[k]) { store[k] = Date.now(); out.push({ json: { customer_id: meta.customer_id, target_tier: 'IDLE' } }); }
    }
  }
}
return out;

const b = { customer_id: Number($json.customer_id), target_tier: $json.target_tier };
if ($json.bundle) b.bundle = $json.bundle;
return { bodyString: JSON.stringify(b) };
